import React, { useEffect, useState } from "react";
import axios from "axios";
import Swal from "sweetalert2";
import { useNavigate } from "react-router-dom";
import { XMarkIcon } from "@heroicons/react/24/solid";

export default function EditProfile() {
  const navigate = useNavigate();

  const [user, setUser] = useState(null);
  const [name, setName] = useState("");

  const [imageFile, setImageFile] = useState(null);
  const [preview, setPreview] = useState("");

  const [currentPassword, setCurrentPassword] = useState("");
  const [newPassword, setNewPassword] = useState("");

  // LOAD PROFILE
  useEffect(() => {
    const stored = JSON.parse(localStorage.getItem("user") || "{}");

    if (!stored?.email) {
      navigate("/");
      return;
    }

    axios
      .get(`http://localhost:8086/user/profile?email=${stored.email}`)
      .then((res) => {
        setUser(res.data);
        setName(res.data.name);
        setPreview(res.data.profileImage);
      })
      .catch(() => {
        Swal.fire("Error", "Failed to load profile", "error");
      });
  }, [navigate]);

  // IMAGE
  const handleImageChange = (e) => {
    const file = e.target.files[0];
    if (!file) return;

    setImageFile(file);
    const reader = new FileReader();
    reader.onloadend = () => setPreview(reader.result);
    reader.readAsDataURL(file);
  };

  // UPDATE PROFILE
  const handleUpdateProfile = async () => {
    try {
      const formData = new FormData();
      formData.append("email", user.email);
      formData.append("name", name);
      if (imageFile) formData.append("image", imageFile);

      const res = await axios.put(
        "http://localhost:8086/user/update-profile",
        formData
      );

      Swal.fire("Success", "Profile updated", "success");
      localStorage.setItem("user", JSON.stringify(res.data));

      navigate("/profile");
    } catch {
      Swal.fire("Error", "Update failed", "error");
    }
  };

  // PASSWORD
  const handleChangePassword = async () => {
    try {
      const res = await axios.put(
        "http://localhost:8086/user/change-password",
        {
          email: user.email,
          currentPassword,
          newPassword,
        }
      );

      Swal.fire("Success", res.data.message, "success");
      setCurrentPassword("");
      setNewPassword("");
    } catch {
      Swal.fire("Error", "Password update failed", "error");
    }
  };

  if (!user) {
    return (
      <div className="min-h-screen flex items-center justify-center">
        Loading profile...
      </div>
    );
  }

  return (
    <div className="fixed inset-0 flex items-center justify-center z-50">

      {/* BACKDROP */}
      <div
        className="absolute inset-0 bg-gradient-to-br from-indigo-200 via-purple-200 to-pink-200"
        onClick={() => navigate("/profile")}
      />

      <div className="absolute inset-0 backdrop-blur-sm" />

      {/* MODAL */}
      <div className="relative w-[900px] max-w-[95%] rounded-3xl bg-white/15 backdrop-blur-2xl border border-white/30 shadow-2xl overflow-hidden">

        {/* HEADER */}
        <div className="flex justify-between items-center px-6 py-4 border-b border-white/20">
          <h2 className="text-white font-semibold text-lg">
            ✨ Edit Profile
          </h2>

          <button onClick={() => navigate("/profile")}>
            <XMarkIcon className="w-6 h-6 text-white/70 hover:text-red-400" />
          </button>
        </div>

        {/* BODY */}
        <div className="grid grid-cols-2 gap-6 p-6">

          {/* LEFT - PROFILE */}
          <div className="bg-white/10 border border-white/20 rounded-2xl p-5">
            <h3 className="text-white font-semibold mb-4">Profile Info</h3>

            {/* IMAGE */}
            <div className="flex flex-col items-center">
              <img
                src={
                  preview ||
                  `https://ui-avatars.com/api/?name=${user.username}`
                }
                className="w-28 h-28 rounded-full border-4 border-white/30 object-cover"
                alt="profile"
              />

              <label className="mt-3 text-white/70 text-sm cursor-pointer hover:text-white">
                Change Photo
                <input
                  type="file"
                  onChange={handleImageChange}
                  className="hidden"
                />
              </label>
            </div>

            {/* NAME */}
            <div className="mt-5">
              <label className="text-white/60 text-sm">Full Name</label>
              <input
                value={name}
                onChange={(e) => setName(e.target.value)}
                className="w-full mt-1 p-3 rounded-xl bg-white/10 text-white border border-white/20 focus:border-indigo-400 outline-none"
              />
            </div>

            {/* EMAIL (READ ONLY) */}
            <div className="mt-4">
              <label className="text-white/60 text-sm">Email</label>
              <input
                value={user.email}
                disabled
                className="w-full mt-1 p-3 rounded-xl bg-white/5 text-white/60 border border-white/10"
              />
            </div>

            {/* SAVE */}
            <button
              onClick={handleUpdateProfile}
              className="w-full mt-5 py-3 rounded-xl bg-gradient-to-r from-indigo-500 to-purple-500 text-white font-semibold hover:opacity-90 transition"
            >
              Save Changes
            </button>
          </div>

          {/* RIGHT - PASSWORD */}
          <div className="bg-white/10 border border-white/20 rounded-2xl p-5">
            <h3 className="text-white font-semibold mb-4">Security</h3>

            <input
              type="password"
              placeholder="Current Password"
              value={currentPassword}
              onChange={(e) => setCurrentPassword(e.target.value)}
              className="w-full mb-3 p-3 rounded-xl bg-white/10 text-white border border-white/20"
            />

            <input
              type="password"
              placeholder="New Password"
              value={newPassword}
              onChange={(e) => setNewPassword(e.target.value)}
              className="w-full mb-4 p-3 rounded-xl bg-white/10 text-white border border-white/20"
            />

            <button
              onClick={handleChangePassword}
              className="w-full py-3 rounded-xl bg-gradient-to-r from-pink-500 to-purple-500 text-white font-semibold hover:opacity-90 transition"
            >
              Update Password
            </button>

            <p className="text-xs text-white/40 mt-4">
              Use a strong password for better security.
            </p>
          </div>

        </div>
      </div>
    </div>
  );
}
